import { app, HttpRequest, HttpResponseInit, InvocationContext } from '@azure/functions';
import { SecretClient } from '@azure/keyvault-secrets';
import { DefaultAzureCredential, ManagedIdentityCredential } from '@azure/identity';

// Initialize Key Vault client with Managed Identity (not DefaultAzureCredential in production)
const keyVaultUrl = process.env.AZURE_KEYVAULT_URL; // Set in App Settings
const credential = new ManagedIdentityCredential(); // Use specific credential type
const secretClient = new SecretClient(keyVaultUrl, credential);

// Cache secrets in memory (refresh every 6 hours)
const secretCache = new Map<string, { value: string; expiresAt: number }>();
const CACHE_TTL_MS = 6 * 60 * 60 * 1000; // 6 hours

async function getSecretSecurely(secretName: string): Promise<string> {
  const cached = secretCache.get(secretName);
  if (cached && Date.now() < cached.expiresAt) {
    return cached.value;
  }

  try {
    // Retrieve specific secret version for immutability
    const secret = await secretClient.getSecret(secretName);

    // Validate secret metadata
    if (secret.properties.enabled === false) {
      throw new Error(`Secret ${secretName} is disabled`);
    }

    if (secret.properties.expiresOn && secret.properties.expiresOn < new Date()) {
      throw new Error(`Secret ${secretName} has expired`);
    }

    // Cache the secret
    secretCache.set(secretName, {
      value: secret.value,
      expiresAt: Date.now() + CACHE_TTL_MS
    });

    return secret.value;
  } catch (error) {
    // Log error without exposing secret values
    console.error(`Failed to retrieve secret ${secretName}:`, {
      errorCode: error.code,
      statusCode: error.statusCode,
      // Never log error.message as it may contain secret data
    });
    throw new Error('Secret retrieval failed');
  }
}

// Example HTTP trigger with secure secret access
export async function httpTrigger(request: HttpRequest, context: InvocationContext): Promise<HttpResponseInit> {
  try {
    // Only retrieve secrets when needed (not at module load)
    const dbConnectionString = await getSecretSecurely('db-connection-string');
    const apiKey = await getSecretSecurely('external-api-key');

    // Use secrets for business logic...
    // NEVER return secrets in HTTP response

    return {
      status: 200,
      body: JSON.stringify({ message: 'Operation successful' })
    };
  } catch (error) {
    context.error('Request failed:', error);
    return {
      status: 500,
      body: JSON.stringify({ error: 'Internal server error' })
    };
  }
}

app.http('httpTrigger', {
  methods: ['GET', 'POST'],
  authLevel: 'function', // Require function key (not anonymous)
  handler: httpTrigger
});

