using Microsoft.Azure.Functions.Worker;
using Microsoft.Azure.Functions.Worker.Http;
using Microsoft.Extensions.Logging;
using System.Net;
using System.Text.RegularExpressions;

public class SecureHttpTrigger
{
    private readonly ILogger<SecureHttpTrigger> _logger;
    private static readonly HashSet<string> BlockedHosts = new(StringComparer.OrdinalIgnoreCase)
    {
        "169.254.169.254", // Azure IMDS
        "metadata.azure.com",
        "169.254.169.254/metadata",
        "localhost",
        "127.0.0.1",
        "0.0.0.0",
        "::1"
    };

    private static readonly Regex InternalIpPattern = new(
        @"^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.)",
        RegexOptions.Compiled
    );

    public SecureHttpTrigger(ILogger<SecureHttpTrigger> logger)
    {
        _logger = logger;
    }

    [Function("SecureHttpTrigger")]
    public async Task<HttpResponseData> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post")] HttpRequestData req,
        FunctionContext context)
    {
        // Example: Secure URL validation to prevent SSRF
        var urlParam = req.Query["url"];

        if (!string.IsNullOrEmpty(urlParam))
        {
            if (!IsUrlSafe(urlParam))
            {
                _logger.LogWarning("Blocked SSRF attempt to: {Url}", SanitizeLog(urlParam));

                var blockedResponse = req.CreateResponse(HttpStatusCode.BadRequest);
                await blockedResponse.WriteStringAsync("Invalid URL");
                return blockedResponse;
            }
        }

        // Your business logic here...

        var response = req.CreateResponse(HttpStatusCode.OK);
        await response.WriteStringAsync("Success");
        return response;
    }

    private bool IsUrlSafe(string url)
    {
        if (!Uri.TryCreate(url, UriKind.Absolute, out var uri))
        {
            return false;
        }

        // Block non-HTTPS URLs (except for specific trusted domains)
        if (uri.Scheme != "https")
        {
            _logger.LogWarning("Blocked non-HTTPS URL: {Scheme}", uri.Scheme);
            return false;
        }

        // Block IMDS and internal endpoints
        if (BlockedHosts.Contains(uri.Host))
        {
            _logger.LogWarning("Blocked access to restricted host: {Host}", uri.Host);
            return false;
        }

        // Block internal IP ranges (RFC 1918)
        if (IPAddress.TryParse(uri.Host, out var ip))
        {
            if (IPAddress.IsLoopback(ip) || IsPrivateIP(ip))
            {
                _logger.LogWarning("Blocked access to internal IP: {IP}", ip);
                return false;
            }
        }

        // Additional checks: DNS rebinding protection
        if (InternalIpPattern.IsMatch(uri.Host))
        {
            return false;
        }

        return true;
    }

    private bool IsPrivateIP(IPAddress ip)
    {
        var bytes = ip.GetAddressBytes();

        // 10.0.0.0/8
        if (bytes[0] == 10) return true;

        // 172.16.0.0/12
        if (bytes[0] == 172 && bytes[1] >= 16 && bytes[1] <= 31) return true;

        // 192.168.0.0/16
        if (bytes[0] == 192 && bytes[1] == 168) return true;

        return false;
    }

    private string SanitizeLog(string input)
    {
        // Remove sensitive patterns from logs
        return Regex.Replace(input, @"(password|token|secret|key)=[^&]+", "$1=***", RegexOptions.IgnoreCase);
    }
}

// Startup configuration for monitoring IMDS access
public class Startup : FunctionsStartup
{
    public override void Configure(IFunctionsHostBuilder builder)
    {
        // Register HTTP client with SSRF protections
        builder.Services.AddHttpClient("SafeClient", client =>
        {
            client.Timeout = TimeSpan.FromSeconds(10);
        })
        .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
        {
            ConnectCallback = async (context, cancellationToken) =>
            {
                // Block connections to IMDS
                if (context.DnsEndPoint.Host == "169.254.169.254")
                {
                    throw new HttpRequestException("Connection to IMDS blocked");
                }

                var socket = new Socket(SocketType.Stream, ProtocolType.Tcp);
                await socket.ConnectAsync(context.DnsEndPoint, cancellationToken);
                return new NetworkStream(socket, ownsSocket: true);
            }
        });
    }
}

