// PowerShell: Audit Function App Settings for plaintext secrets
$functionApps = Get-AzFunctionApp
foreach ($app in $functionApps) {
    $settings = Get-AzFunctionAppSetting -Name $app.Name -ResourceGroupName $app.ResourceGroup

    foreach ($setting in $settings.GetEnumerator()) {
        # Check for plaintext secrets (not Key Vault references)
        if ($setting.Value -notlike "@Microsoft.KeyVault*" -and 
            ($setting.Name -like "*password*" -or 
             $setting.Name -like "*secret*" -or 
             $setting.Name -like "*key*" -or
             $setting.Name -like "*token*" -or
             $setting.Name -like "*connectionstring*")) {

            Write-Warning "Plaintext secret detected in $($app.Name): $($setting.Name)"
        }
    }
}

