# Secure deployment package workflow

# 1. Build and package Function App
func pack --output ./publish/function-app.zip

# 2. Calculate package hash for integrity verification
$packageHash = (Get-FileHash ./publish/function-app.zip -Algorithm SHA256).Hash
Write-Host "Package SHA256: $packageHash"

# 3. Upload to private storage account (no public access)
$storageAccount = Get-AzStorageAccount -ResourceGroupName "rg-secure-prod" -Name "stsecuredeployments"
$ctx = $storageAccount.Context

$containerName = "deployments"
$blobName = "function-app-$(Get-Date -Format 'yyyyMMddHHmmss').zip"

Set-AzStorageBlobContent `
    -File "./publish/function-app.zip" `
    -Container $containerName `
    -Blob $blobName `
    -Context $ctx `
    -Properties @{"ContentMD5" = $packageHash}

# 4. Generate time-limited SAS token (expires in 1 hour)
$sasToken = New-AzStorageBlobSASToken `
    -Container $containerName `
    -Blob $blobName `
    -Permission r `
    -StartTime (Get-Date) `
    -ExpiryTime (Get-Date).AddHours(1) `
    -Context $ctx

$packageUrl = "https://stsecuredeployments.blob.core.windows.net/$containerName/$blobName$sasToken"

# 5. Update Function App with package URL
Update-AzFunctionAppSetting `
    -Name "func-secure-prod" `
    -ResourceGroupName "rg-secure-prod" `
    -AppSetting @{
        "WEBSITE_RUN_FROM_PACKAGE" = $packageUrl
        "DEPLOYMENT_PACKAGE_HASH" = $packageHash
        "DEPLOYMENT_TIMESTAMP" = (Get-Date -Format o)
    }

# 6. Verify deployment integrity (in Function App startup code)
<#
const crypto = require('crypto');
const https = require('https');

async function verifyDeploymentIntegrity() {
    const expectedHash = process.env.DEPLOYMENT_PACKAGE_HASH;
    const packageUrl = process.env.WEBSITE_RUN_FROM_PACKAGE;

    if (!expectedHash || !packageUrl) {
        throw new Error('Deployment verification failed: missing metadata');
    }

    // Download package and verify hash
    return new Promise((resolve, reject) => {
        https.get(packageUrl, (response) => {
            const hash = crypto.createHash('sha256');
            response.on('data', (chunk) => hash.update(chunk));
            response.on('end', () => {
                const actualHash = hash.digest('hex').toUpperCase();
                if (actualHash !== expectedHash) {
                    reject(new Error('Package integrity check failed'));
                } else {
                    resolve();
                }
            });
        }).on('error', reject);
    });
}
#>

